  if (lever.location === "room:gate") {
    return "You rummage through the 'heap of junk'. Most of it is indeed junk—shards of dimensional glass, bent copper wire, and empty crates. However, you find a long iron bar that isn't as wedged as the rest of it. You pull it free. It's a rusty lever.";
  } else {
    return "You poke around the heap of junk again, but there's nothing else in there that looks remotely useful. Just old crates and the heavy, jammed mechanism of that lead-balled bar.";
